export declare const docsTemplate = "\"use client\";\nimport { useEffect, useState, useCallback } from \"react\";\nimport { Flex, Space } from \"cherry-styled-components/src/lib\";\nimport Markdown from \"react-markdown\";\nimport remarkGfm from \"remark-gfm\";\nimport rehypeRaw from \"rehype-raw\";\nimport { Code } from \"@/components/layout/Code\";\nimport { Card, CardProps } from \"@/components/layout/Card\";\nimport { \n  DocsContainer,\n  StyledMarkdownContainer,\n  StyledIndexSidebar,\n  StyledIndexSidebarLink,\n  StyledIndexSidebarLabel,\n} from \"@/components/layout/DocsComponents\";\n\ninterface DocsProps {\n  content: string;\n}\n\ninterface Heading {\n  id: string;\n  text: string;\n  level: number;\n}\n\nfunction generateId(text: string): string {\n  return text\n    .toLowerCase()\n    .replace(/[^\\w\\s-]/g, \"\")\n    .replace(/\\s+/g, \"-\")\n    .trim();\n}\n\nfunction extractHeadings(content: string): Heading[] {\n  const headingRegex = /^(#{1,6})\\s+(.+)$/gm;\n  const headings: Heading[] = [];\n  let match;\n\n  while ((match = headingRegex.exec(content)) !== null) {\n    const level = match[1].length;\n    const text = match[2].trim();\n    const id = generateId(text);\n    headings.push({ id, text, level });\n  }\n\n  return headings;\n}\n\nfunction useActiveHeading(headings: Heading[]): string {\n  const [activeId, setActiveId] = useState<string>(\"\");\n\n  const handleScroll = useCallback(() => {\n    if (headings.length === 0) return;\n\n    const headingElements = headings\n      .map((heading) => document.getElementById(heading.id))\n      .filter(Boolean);\n\n    if (headingElements.length === 0) return;\n\n    const windowHeight = window.innerHeight;\n\n    const visibleHeadings = headingElements.filter((element) => {\n      if (!element) return false;\n\n      const rect = element.getBoundingClientRect();\n      const elementTop = rect.top;\n      const elementBottom = rect.bottom;\n\n      return elementTop < windowHeight && elementBottom > -50;\n    });\n\n    if (visibleHeadings.length > 0) {\n      let closestHeading = visibleHeadings[0];\n      let closestDistance = Math.abs(\n        closestHeading!.getBoundingClientRect().top,\n      );\n\n      for (const heading of visibleHeadings) {\n        if (!heading) continue;\n        const distance = Math.abs(heading.getBoundingClientRect().top);\n        if (\n          distance < closestDistance &&\n          heading.getBoundingClientRect().top <= windowHeight * 0.3\n        ) {\n          closestDistance = distance;\n          closestHeading = heading;\n        }\n      }\n\n      setActiveId(closestHeading!.id);\n      return;\n    }\n\n    let currentActiveId = headings[0].id;\n\n    for (const element of headingElements) {\n      if (!element) continue;\n\n      const rect = element.getBoundingClientRect();\n      if (rect.top <= 0) {\n        currentActiveId = element.id;\n      } else {\n        break;\n      }\n    }\n\n    setActiveId(currentActiveId);\n  }, [headings]);\n\n  useEffect(() => {\n    if (headings.length === 0) return;\n\n    handleScroll();\n\n    let timeoutId: NodeJS.Timeout;\n    const throttledHandleScroll = () => {\n      clearTimeout(timeoutId);\n      timeoutId = setTimeout(handleScroll, 50);\n    };\n\n    window.addEventListener(\"scroll\", throttledHandleScroll);\n    window.addEventListener(\"resize\", handleScroll);\n\n    return () => {\n      window.removeEventListener(\"scroll\", throttledHandleScroll);\n      window.removeEventListener(\"resize\", handleScroll);\n      clearTimeout(timeoutId);\n    };\n  }, [handleScroll, headings]);\n\n  return activeId;\n}\n\nconst defaultComponents = {\n  Card: ({\n    title,\n    icon,\n    children,\n  }: CardProps) => (\n    <Card title={title} icon={icon}>\n      {children}\n    </Card>\n  ),\n};\n  \nfunction Docs({ content }: DocsProps) {\n  const [headings, setHeadings] = useState<Heading[]>([]);\n  const activeHeadingId = useActiveHeading(headings);\n\n  useEffect(() => {\n    if (content) {\n      const extractedHeadings = extractHeadings(content);\n      setHeadings(extractedHeadings);\n    }\n  }, [content]);\n\n  const handleHeadingClick = (headingId: string) => {\n    const element = document.getElementById(headingId);\n    if (element) {\n      element.scrollIntoView({\n        behavior: \"smooth\",\n        block: \"start\",\n      });\n    }\n  };\n\n  return (\n    <>\n      <DocsContainer>\n        <Flex $gap={20}>\n          <StyledMarkdownContainer>\n          {content && (\n            <Markdown\n              remarkPlugins={[remarkGfm]}\n              rehypePlugins={[rehypeRaw]}\n              components={{\n                code(props) {\n                  const { children, className, node, ...rest } = props;\n                  const match = /language-(\\w+)/.exec(className || \"\");\n                  return match ? (\n                  <Code\n                      {...rest}\n                      className={className}\n                      code={String(children).replace(/\\n$/, \"\")}\n                      language={match[1]}\n                    />\n                  ) : (\n                    <code {...rest} className={className}>\n                      {children}\n                    </code>\n                  );\n                },\n                h1: ({ children, ...props }) => {\n                  const id = generateId(String(children));\n                  return (\n                    <h1 id={id} {...props}>\n                      {children}\n                    </h1>\n                  );\n                },\n                h2: ({ children, ...props }) => {\n                  const id = generateId(String(children));\n                  return (\n                    <h2 id={id} {...props}>\n                      {children}\n                    </h2>\n                  );\n                },\n                h3: ({ children, ...props }) => {\n                  const id = generateId(String(children));\n                  return (\n                    <h3 id={id} {...props}>\n                      {children}\n                    </h3>\n                  );\n                },\n                h4: ({ children, ...props }) => {\n                  const id = generateId(String(children));\n                  return (\n                    <h4 id={id} {...props}>\n                      {children}\n                    </h4>\n                  );\n                },\n                h5: ({ children, ...props }) => {\n                  const id = generateId(String(children));\n                  return (\n                    <h5 id={id} {...props}>\n                      {children}\n                    </h5>\n                  );\n                },\n                h6: ({ children, ...props }) => {\n                  const id = generateId(String(children));\n                  return (\n                    <h6 id={id} {...props}>\n                      {children}\n                    </h6>\n                  );\n                },\n                ...Object.fromEntries(\n                  Object.entries(defaultComponents).map(\n                    ([name, Component]) => [name.toLowerCase(), Component],\n                  ),\n                ),\n              }}\n            >\n              {content}\n            </Markdown>\n           )}\n          </StyledMarkdownContainer>\n        </Flex>\n      </DocsContainer>\n      <StyledIndexSidebar>\n        {headings?.length > 0 && (\n          <>\n            <StyledIndexSidebarLabel>On this page</StyledIndexSidebarLabel>\n            <Space $size={20} />\n          </>\n        )}\n        {headings.map((heading, index) => (\n          <li\n            key={index}\n            style={{\n              paddingLeft: `${(heading.level - 1) * 16}px`,\n            }}\n          >\n            <StyledIndexSidebarLink\n              href={`#${heading.id}`}\n              onClick={(e) => {\n                e.preventDefault();\n                handleHeadingClick(heading.id);\n              }}\n              $isActive={activeHeadingId === heading.id}\n            >\n              {heading.text}\n            </StyledIndexSidebarLink>\n          </li>\n        ))}\n      </StyledIndexSidebar>\n    </>\n  );\n}\n\nexport { Docs };\n";
